+/// Compression level settings
+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+pub enum CompressionLevel {
+    /// No compression
+    None,
+    /// Fast compression (lower ratio)
+    Fast,
+    /// Balanced compression
+    Balanced,
+    /// Best compression (slower)
+    Best,
+}
+
+impl Default for CompressionLevel {
+    fn default() -> Self {
+        Self::Balanced
